import "./Navbar.css";

const Navbar = () => {
  return (
    <>
      <div className="nav-left">
            <a href="#header"></a>
          <a href="#contact" className="nav-item">contact</a>
          <a href="#projects" className="nav-item">projects</a>
          <a href="#about" className="nav-item">about me</a>
        </div>
    </>
  );
};

export default Navbar;
